SELECT c.id, u.id, 'french-b2-dilemmes-ethiques-grammar', 'grammar', 'Hypothèse avec si + plus-que-parfait et le conditionnel passé', 'Formuler une hypothèse irréelle sur le passé et exprimer un regret ou un reproche.', 74, 30, 'free', 14, true, NULL, 'Pour une hypothèse irréelle sur le passé : « Si + plus-que-parfait, conditionnel passé » : « Si j’avais su, je serais venu. » Le conditionnel passé (avoir/être au conditionnel présent + participe passé) exprime aussi un regret ou un reproche : « J’aurais dû lui parler. Tu aurais pu me le dire. »', '["Si j’avais su...","..., j’aurais...","J’aurais dû...","Tu aurais pu..."]'::jsonb
FROM public.courses c
JOIN public.languages l ON l.id = c.language_id
JOIN public.levels lv ON lv.id = c.level_id
JOIN public.course_units u ON u.course_id = c.id AND u.slug = 'dilemmes-ethiques'
WHERE l.code = 'french' AND lv.code = 'B2'
ON CONFLICT (slug) DO UPDATE SET
  unit_id = EXCLUDED.unit_id, skill = EXCLUDED.skill, title = EXCLUDED.title, description = EXCLUDED.description,
  order_index = EXCLUDED.order_index, xp_reward = EXCLUDED.xp_reward, access_tier = EXCLUDED.access_tier,
