SELECT c.id, u.id, 'french-b2-bilan-et-projets-davenir-grammar', 'grammar', 'Récapitulatif : hypothèses complexes et expressions de bilan', 'Réviser les hypothèses avec si + plus-que-parfait et les expressions de bilan personnel.', 124, 30, 'free', 14, true, NULL, 'Ce récapitulatif combine les points du niveau B2 : hypothèse irréelle du passé (si + plus-que-parfait, conditionnel passé), expressions de bilan (avec le recul, en fin de compte), et détermination (être déterminé(e) à + infinitif) : « Si j’avais renoncé, je n’aurais jamais grandi. Avec le recul, je suis déterminée à continuer. »', '["Si j’avais renoncé, je n’aurais jamais...","Avec le recul...","En fin de compte...","Je suis déterminé(e) à..."]'::jsonb
FROM public.courses c
JOIN public.languages l ON l.id = c.language_id
JOIN public.levels lv ON lv.id = c.level_id
JOIN public.course_units u ON u.course_id = c.id AND u.slug = 'bilan-et-projets-davenir'
WHERE l.code = 'french' AND lv.code = 'B2'
ON CONFLICT (slug) DO UPDATE SET
  unit_id = EXCLUDED.unit_id, skill = EXCLUDED.skill, title = EXCLUDED.title, description = EXCLUDED.description,
  order_index = EXCLUDED.order_index, xp_reward = EXCLUDED.xp_reward, access_tier = EXCLUDED.access_tier,
  estimated_minutes = EXCLUDED.estimated_minutes, is_published = true,
  mission = EXCLUDED.mission, grammar_note = EXCLUDED.grammar_note, phrases = EXCLUDED.phrases;
