-- ---------------------------------------------------------------------
-- 6. Scoped cleanup: remove only French B2 lesson_sections/exercises
--    before re-inserting them fresh below (idempotent re-run). Scoped by
--    course_lessons.slug LIKE - never touches other levels/languages.
-- ---------------------------------------------------------------------
DELETE FROM public.lesson_sections
WHERE lesson_id IN (
  SELECT id FROM public.course_lessons WHERE slug LIKE 'french-b2-%'
);
DELETE FROM public.exercises
WHERE lesson_id IN (
  SELECT id FROM public.course_lessons WHERE slug LIKE 'french-b2-%'
);

