VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-debats-de-societe-dialogue'), 'intro', 0, 'Après la session, Camila appelle Karim pour lui raconter son premier débat en français.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-debats-de-societe-dialogue'), 'dialogue_line', 0, 'Camila', 'J’ai réussi à débattre en français devant des inconnus, tu te rends compte ?', 'Logré debatir en francés frente a desconocidos, ¿te das cuenta?');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-debats-de-societe-dialogue'), 'dialogue_line', 1, 'Karim', 'C’est génial, je suis vraiment fier de toi !', '¡Es genial, estoy muy orgulloso de ti!');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-debats-de-societe-dialogue'), 'dialogue_line', 2, 'Camila', 'J’étais nerveuse au début, mais j’ai fini par prendre confiance.', 'Estaba nerviosa al principio, pero terminé ganando confianza.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
