INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-litterature-francophone-writing'), 'dialogue_line', 0, 'Modèle', 'Ce roman évoque le thème du déracinement à travers l’histoire d’une jeune femme partagée entre deux cultures. L’autrice a expliqué qu’elle voulait montrer qu’on pouvait appartenir à plusieurs mondes à la fois. Ce livre auquel je pense souvent m’a beaucoup marquée.', 'Esta novela evoca el tema del desarraigo a través de la historia de una joven dividida entre dos culturas. La autora explicó que quería mostrar que se podía pertenecer a varios mundos a la vez. Este libro en el que pienso a menudo me marcó mucho.');
