INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-histoire-et-memoire-writing'), 'dialogue_line', 0, 'Modèle', 'Celle dont je me souviens le mieux, c’est l’histoire que ma grand-mère m’a racontée un dimanche après-midi. On m’avait longtemps caché cette partie de notre histoire familiale. Aujourd’hui, je comprends que cette histoire fait partie de qui je suis.', 'La que más recuerdo es la historia que mi abuela me contó un domingo por la tarde. Durante mucho tiempo me habían ocultado esa parte de nuestra historia familiar. Hoy entiendo que esa historia es parte de quien soy.');
