INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-ecologie-et-engagement-citoyen-speaking'), 'dialogue_line', 0, 'Toi', 'Je m’engage pour cette cause afin que les générations futures puissent en profiter aussi. Je ne pense pas qu’on puisse résoudre ce problème sans action collective.', 'Me comprometo con esta causa para que las generaciones futuras también puedan disfrutarla. No creo que podamos resolver este problema sin acción colectiva.');
INSERT INTO public.lesson_sections (lesson_id, type, order_index, speaker, line, translation)
VALUES ((SELECT id FROM public.course_lessons WHERE slug = 'french-b2-ecologie-et-engagement-citoyen-writing'), 'dialogue_line', 0, 'Modèle', 'Nous vous écrivons afin que nos deux associations puissent collaborer sur ce projet environnemental. Je ne pense pas que ces problèmes puissent être résolus isolément. Notre groupe mène déjà des actions concrètes sur le terrain, et nous espérons vivement collaborer avec vous.', 'Le escribimos para que nuestras dos asociaciones puedan colaborar en este proyecto ambiental. No creo que estos problemas puedan resolverse de forma aislada. Nuestro grupo ya lleva a cabo acciones concretas sobre el terreno, y esperamos con interés colaborar con ustedes.');
